import{_ as s,o as t,c as n,ae as a}from"./chunks/framework.CiBL6oPQ.js";const u=JSON.parse('{"title":"Generator Flow Documentation","description":"","frontmatter":{},"headers":[],"relativePath":"internal/generatorFlow.md","filePath":"internal/generatorFlow.md"}'),o={name:"internal/generatorFlow.md"};function r(l,e,i,c,d,p){return t(),n("div",null,[...e[0]||(e[0]=[a(`<h1 id="generator-flow-documentation" tabindex="-1">Generator Flow Documentation <a class="header-anchor" href="#generator-flow-documentation" aria-label="Permalink to &quot;Generator Flow Documentation&quot;">​</a></h1><p>This document outlines the internal flow of the <code>nodejs-quickstart-structure</code> generator, including user options, the step-by-step generation process, and the resulting codebase structures.</p><h2 id="_1-technologies-used" tabindex="-1">1. Technologies Used <a class="header-anchor" href="#_1-technologies-used" aria-label="Permalink to &quot;1. Technologies Used&quot;">​</a></h2><p>The <code>nodejs-quickstart-structure</code> CLI is built using the following key technologies:</p><ul><li><strong><a href="https://nodejs.org/" target="_blank" rel="noreferrer">Node.js</a></strong>: The runtime environment.</li><li><strong><a href="https://github.com/tj/commander.js" target="_blank" rel="noreferrer">Commander.js</a></strong> (<code>^13.1.0</code>): For parsing command-line arguments and options.</li><li><strong><a href="https://github.com/SBoudrias/Inquirer.js" target="_blank" rel="noreferrer">Inquirer.js</a></strong> (<code>^12.4.1</code>): For interactive command-line user interface (prompts).</li><li><strong><a href="https://github.com/chalk/chalk" target="_blank" rel="noreferrer">Chalk</a></strong> (<code>^5.4.1</code>): For terminal string styling (color output).</li><li><strong><a href="https://github.com/mde/ejs" target="_blank" rel="noreferrer">EJS (Embedded JavaScript templates)</a></strong> (<code>^3.1.10</code>): For templating files (dynamic content generation).</li><li><strong><a href="https://github.com/jprichardson/node-fs-extra" target="_blank" rel="noreferrer">fs-extra</a></strong> (<code>^11.3.0</code>): For enhanced file system methods (copy, ensureDir, etc.).</li></ul><h2 id="_2-user-choices-cases" tabindex="-1">2. User Choices (Cases) <a class="header-anchor" href="#_2-user-choices-cases" aria-label="Permalink to &quot;2. User Choices (Cases)&quot;">​</a></h2><p>The generator prompts the user for the following configurations. These determine the logic and structure of the generated project.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Option</th><th style="text-align:left;">Choices</th><th style="text-align:left;">Default</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Project Name</strong></td><td style="text-align:left;">Input String</td><td style="text-align:left;"><code>nodejs-service</code></td><td style="text-align:left;">Name of the project directory.</td></tr><tr><td style="text-align:left;"><strong>Language</strong></td><td style="text-align:left;"><code>JavaScript</code>, <code>TypeScript</code></td><td style="text-align:left;"><code>TypeScript</code></td><td style="text-align:left;">The programming language to use.</td></tr><tr><td style="text-align:left;"><strong>Architecture</strong></td><td style="text-align:left;"><code>MVC</code>, <code>Clean Architecture</code></td><td style="text-align:left;"><code>MVC</code></td><td style="text-align:left;">The architectural pattern.</td></tr><tr><td style="text-align:left;"><strong>View Engine</strong></td><td style="text-align:left;"><code>None</code>, <code>EJS</code>, <code>Pug</code></td><td style="text-align:left;"><code>None</code></td><td style="text-align:left;">(MVC Only) Template engine for server-side rendering.</td></tr><tr><td style="text-align:left;"><strong>Database</strong></td><td style="text-align:left;"><code>None</code>, <code>MySQL</code>, <code>PostgreSQL</code>, <code>MongoDB</code></td><td style="text-align:left;"><code>None</code></td><td style="text-align:left;">The primary database.</td></tr><tr><td style="text-align:left;"><strong>Database Name</strong></td><td style="text-align:left;">Input String</td><td style="text-align:left;"><code>demo</code></td><td style="text-align:left;">The name of the database to use/create.</td></tr><tr><td style="text-align:left;"><strong>Communication</strong></td><td style="text-align:left;"><code>REST APIs</code>, <code>GraphQL</code>, <code>Kafka</code></td><td style="text-align:left;"><code>REST APIs</code></td><td style="text-align:left;">The primary communication method.</td></tr><tr><td style="text-align:left;"><strong>Caching Layer</strong></td><td style="text-align:left;"><code>None</code>, <code>Redis</code>, <code>Memory Cache</code></td><td style="text-align:left;"><code>None</code></td><td style="text-align:left;">(If DB selected) Caching solution.</td></tr><tr><td style="text-align:left;"><strong>CI/CD Provider</strong></td><td style="text-align:left;"><code>None</code>, <code>GitHub Actions</code>, <code>Jenkins</code></td><td style="text-align:left;"><code>None</code></td><td style="text-align:left;">Setup for Continuous Integration/Deployment.</td></tr></tbody></table><h2 id="_3-main-generator-flow" tabindex="-1">3. Main Generator Flow <a class="header-anchor" href="#_3-main-generator-flow" aria-label="Permalink to &quot;3. Main Generator Flow&quot;">​</a></h2><p>The <code>generateProject</code> function in <code>lib/generator.js</code> executes the following steps:</p><ol><li><strong>Create Project Directory</strong>: Ensures the directory does not already exist and creates it.</li><li><strong>Select &amp; Copy Base Structure</strong>: <ul><li>Based on <strong>Architecture</strong> (<code>mvc</code>/<code>clean-architecture</code>) and <strong>Language</strong> (<code>js</code>/<code>ts</code>), it selects the appropriate template from <code>templates/{arch}/{lang}</code>.</li><li>Copies the entire base template to the target directory.</li></ul></li><li><strong>Render <code>package.json</code></strong>: <ul><li>Uses <code>templates/common/package.json.ejs</code>.</li><li>Injects dependencies based on User Choices (DB drivers, view engines, etc.).</li></ul></li><li><strong>Render <code>docker-compose.yml</code></strong>: <ul><li>Uses <code>templates/common/docker-compose.yml.ejs</code>.</li><li>Configures services (DB, Zookeeper/Kafka) based on selection.</li><li><strong>Note</strong>: If Database is <code>None</code>, DB services are excluded.</li></ul></li><li><strong>Render <code>README.md</code></strong>: <ul><li>Generates custom documentation specific to the selected stack.</li></ul></li><li><strong>Render <code>src/index.{js|ts}</code></strong>: <ul><li>Processes the entry point file to wire up the selected DB, Architecture, and Communication type.</li><li><strong>GraphQL</strong>: Wires up Apollo Server middleware with <code>formatError</code> hook for centralized error handling.</li><li><strong>REST APIs / Kafka</strong>: Registers <code>app.use(errorMiddleware)</code> at the end of the Express chain.</li></ul></li><li><strong>Error Middleware setup</strong> (<code>renderErrorMiddleware</code>): <ul><li>Processes <code>errorMiddleware.{ts|js}.ejs</code> template from the target directory&#39;s <code>src/utils/</code> path.</li><li>Renders to <code>src/utils/errorMiddleware.{ts|js}</code> in the generated project.</li><li><strong>Clean Architecture</strong>: Also handles <code>src/infrastructure/webserver/middleware/errorMiddleware.{js}</code> path.</li></ul></li><li><strong>Dynamic Component Generation</strong>: <ul><li><strong>MVC</strong>: Generates <code>userController</code> (imports specific DB service, uses <code>next(error)</code>).</li><li><strong>Clean Architecture</strong>: Generates <code>UserRepository</code> (infrastructure layer implementation).</li><li><strong>Clean Architecture (JS only)</strong>: Generates <code>server.js</code> (webserver setup).</li></ul></li><li><strong>Communication Setup</strong>: <ul><li><strong>GraphQL</strong>: <ul><li>Generates Apollo Server v4 schema (<code>typeDefs</code>) and resolvers.</li><li>Configures <code>formatError</code> hook with <code>unwrapResolverError</code> for structured error mapping.</li><li>Automatically embeds Apollo Sandbox with local CSP headers (no CDN dependency).</li></ul></li><li><strong>Kafka</strong>: <ul><li>Copies Kafka client/service templates.</li><li><strong>Clean Architecture Restructuring</strong>: <ul><li>Moves service to <code>src/infrastructure/messaging</code>.</li><li>Moves config to <code>src/infrastructure/config</code>.</li><li>Removes REST-specific folders (<code>interfaces/routes</code>, <code>interfaces/controllers</code>).</li></ul></li><li><strong>MVC Cleanup</strong>: <ul><li>If no View Engine is selected, removes <code>src/controllers</code> and <code>src/routes</code> (assumes pure worker).</li></ul></li></ul></li></ul></li><li><strong>Common Configuration</strong>: <ul><li>Copies <code>.gitignore</code>, <code>.dockerignore</code>, <code>Dockerfile</code>.</li><li>Copies <code>tsconfig.json</code> (if TypeScript).</li></ul></li><li><strong>Database Setup</strong>: <ul><li><strong>MongoDB</strong>: Sets up <code>migrate-mongo-config.js</code> and initial migration script.</li><li><strong>SQL (MySQL/Postgres)</strong>: Sets up <code>flyway/sql</code> directory and copies initial SQL migration files.</li><li><strong>None</strong>: Skips migration setup.</li></ul></li><li><strong>Caching Setup</strong>: <ul><li><strong>Redis</strong>: <ul><li>Injects <code>ioredis</code> dependency into <code>package.json</code>.</li><li>Generates <code>redisClient.{js|ts}</code> config.</li><li><strong>MVC</strong>: Injects generic caching logic into <code>userController</code>.</li><li><strong>Clean Architecture</strong>: Overwrites UseCases with caching-enabled versions.</li></ul></li><li><strong>Memory Cache</strong>: <ul><li>Injects <code>node-cache</code> dependency.</li><li>Generates <code>memoryCache.{js|ts}</code> config.</li><li><strong>MVC/Clean</strong>: Consumes the generic abstraction injected above.</li></ul></li></ul></li><li><strong>Database Connection Config</strong>: <ul><li>Renders <code>database.{js|ts}</code> or <code>mongoose.{js|ts}</code> based on DB selection.</li><li>Places it in <code>src/config</code> (MVC) or <code>src/infrastructure/database</code> (Clean Arch).</li><li><strong>None</strong>: Skips this step.</li></ul></li><li><strong>Model Generation</strong>: <ul><li>Renders <code>User</code> model (Mongoose schema or Sequelize/TypeORM model) in the appropriate directory.</li><li><strong>None</strong>: Generates a simple Mock Entity/Model class with in-memory data for testing.</li></ul></li><li><strong>View Engine Setup (MVC)</strong>: <ul><li>If selected, copies views (<code>views/ejs</code> or <code>views/pug</code>) and <code>public</code> assets.</li></ul></li><li><strong>Swagger Config</strong> (<code>renderSwaggerConfig</code>): <ul><li>If <strong>REST APIs</strong> is selected, generates <code>swagger.yml</code> and <code>swagger.{ts|js}</code> config.</li><li>Cleans up <code>.ejs</code> template copies for non-REST configs (GraphQL, Kafka).</li></ul></li><li><strong>Code Quality Setup</strong>: <ul><li>Generates <code>.eslintrc.json</code>, <code>.prettierrc</code>, <code>.lintstagedrc</code>.</li></ul></li><li><strong>Test Setup</strong>: <ul><li>Generates <code>jest.config.js</code> and a sample <code>health.test.{js|ts}</code>.</li></ul></li><li><strong>CI/CD Setup</strong>: <ul><li>Helper: <code>setupCiCd</code></li><li>Checks <code>config.ciProvider</code>: <ul><li><strong>GitHub Actions</strong>: Copies <code>.github/workflows/ci.yml</code>.</li><li><strong>Jenkins</strong>: Renders <code>Jenkinsfile</code>.</li><li><strong>GitLab CI</strong>: Renders <code>.gitlab-ci.yml</code> if selected.</li></ul></li></ul></li></ol><h2 id="_4-typescript-vs-javascript-generation-steps" tabindex="-1">4. TypeScript vs JavaScript Generation Steps <a class="header-anchor" href="#_4-typescript-vs-javascript-generation-steps" aria-label="Permalink to &quot;4. TypeScript vs JavaScript Generation Steps&quot;">​</a></h2><p>The logic handles language differences via conditional checks and file extensions (<code>langExt</code> variable).</p><table tabindex="0"><thead><tr><th style="text-align:left;">Step</th><th style="text-align:left;">JavaScript (<code>js</code>)</th><th style="text-align:left;">TypeScript (<code>ts</code>)</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Base Template</strong></td><td style="text-align:left;"><code>templates/{arch}/js</code></td><td style="text-align:left;"><code>templates/{arch}/ts</code></td></tr><tr><td style="text-align:left;"><strong>Entry Point</strong></td><td style="text-align:left;"><code>src/index.js</code></td><td style="text-align:left;"><code>src/index.ts</code></td></tr><tr><td style="text-align:left;"><strong>tsconfig.json</strong></td><td style="text-align:left;">Skipped</td><td style="text-align:left;">Copied from <code>templates/common/tsconfig.json</code></td></tr><tr><td style="text-align:left;"><strong>Linting</strong></td><td style="text-align:left;">Standard JS config</td><td style="text-align:left;">TS-specific parser and plugins in <code>.eslintrc</code></td></tr><tr><td style="text-align:left;"><strong>Database Config</strong></td><td style="text-align:left;"><code>mongoose.js</code> / <code>database.js</code></td><td style="text-align:left;"><code>mongoose.ts</code> / <code>database.ts</code></td></tr><tr><td style="text-align:left;"><strong>Models/Controllers</strong></td><td style="text-align:left;"><code>.js</code> extension</td><td style="text-align:left;"><code>.ts</code> extension</td></tr><tr><td style="text-align:left;"><strong>Build Step</strong></td><td style="text-align:left;">No compilation needed</td><td style="text-align:left;">Compilation typically handled by <code>tsc</code> or <code>ts-node</code> in dev</td></tr></tbody></table><h2 id="_5-possible-codebase-structures" tabindex="-1">5. Possible Codebase Structures <a class="header-anchor" href="#_5-possible-codebase-structures" aria-label="Permalink to &quot;5. Possible Codebase Structures&quot;">​</a></h2><p>The final structure depends heavily on <strong>Architecture</strong>, <strong>Communication</strong>, and <strong>View Engine</strong>.</p><h3 id="case-a-mvc-rest-api" tabindex="-1">Case A: MVC (REST API) <a class="header-anchor" href="#case-a-mvc-rest-api" aria-label="Permalink to &quot;Case A: MVC (REST API)&quot;">​</a></h3><p>Standard architecture for web APIs.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>project-name/</span></span>
<span class="line"><span>├── src/</span></span>
<span class="line"><span>│   ├── config/         # Database, Redis, Swagger, etc.</span></span>
<span class="line"><span>│   ├── controllers/    # Request handlers (use next(error))</span></span>
<span class="line"><span>│   ├── errors/         # ApiError, NotFoundError, BadRequestError</span></span>
<span class="line"><span>│   ├── models/         # Database models</span></span>
<span class="line"><span>│   ├── routes/         # Express routes</span></span>
<span class="line"><span>│   ├── utils/</span></span>
<span class="line"><span>│   │   ├── errorMiddleware.{ts|js}  # Global error handler</span></span>
<span class="line"><span>│   │   ├── logger.{ts|js}</span></span>
<span class="line"><span>│   │   └── httpCodes.{ts|js}</span></span>
<span class="line"><span>│   └── index.js|ts     # Entry point (registers errorMiddleware last)</span></span>
<span class="line"><span>├── tests/              # Jest tests</span></span>
<span class="line"><span>├── package.json</span></span>
<span class="line"><span>├── Dockerfile</span></span>
<span class="line"><span>└── docker-compose.yml</span></span></code></pre></div><h3 id="case-a2-mvc-graphql" tabindex="-1">Case A2: MVC (GraphQL) <a class="header-anchor" href="#case-a2-mvc-graphql" aria-label="Permalink to &quot;Case A2: MVC (GraphQL)&quot;">​</a></h3><p>Apollo Server v4 mounted as Express middleware.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>project-name/</span></span>
<span class="line"><span>├── src/</span></span>
<span class="line"><span>│   ├── config/         # Database, Redis config</span></span>
<span class="line"><span>│   ├── controllers/    # GraphQL resolver backing logic (throws errors)</span></span>
<span class="line"><span>│   ├── errors/         # ApiError, NotFoundError, BadRequestError</span></span>
<span class="line"><span>│   ├── graphql/</span></span>
<span class="line"><span>│   │   ├── schema/     # typeDefs</span></span>
<span class="line"><span>│   │   └── resolvers/  # user.resolvers (calls controllers, throws errors)</span></span>
<span class="line"><span>│   ├── models/</span></span>
<span class="line"><span>│   ├── utils/</span></span>
<span class="line"><span>│   │   ├── errorMiddleware.{ts|js}  # Express-level fallback error handler</span></span>
<span class="line"><span>│   │   └── logger.{ts|js}</span></span>
<span class="line"><span>│   └── index.js|ts     # Apollo Server + formatError hook</span></span>
<span class="line"><span>└── ...</span></span></code></pre></div><h3 id="case-b-mvc-web-app-with-views" tabindex="-1">Case B: MVC (Web App with Views) <a class="header-anchor" href="#case-b-mvc-web-app-with-views" aria-label="Permalink to &quot;Case B: MVC (Web App with Views)&quot;">​</a></h3><p>Includes frontend views rendered on the server.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>project-name/</span></span>
<span class="line"><span>├── public/             # CSS, JS, Images</span></span>
<span class="line"><span>├── src/</span></span>
<span class="line"><span>│   ├── config/</span></span>
<span class="line"><span>│   ├── controllers/</span></span>
<span class="line"><span>│   ├── models/</span></span>
<span class="line"><span>│   ├── routes/</span></span>
<span class="line"><span>│   ├── views/          # EJS or Pug templates</span></span>
<span class="line"><span>│   └── index.js|ts</span></span>
<span class="line"><span>└── ...</span></span></code></pre></div><h3 id="case-c-clean-architecture-rest-api" tabindex="-1">Case C: Clean Architecture (REST API) <a class="header-anchor" href="#case-c-clean-architecture-rest-api" aria-label="Permalink to &quot;Case C: Clean Architecture (REST API)&quot;">​</a></h3><p>Separation of concerns with Domain, Use Cases, and Infrastructure.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>project-name/</span></span>
<span class="line"><span>├── src/</span></span>
<span class="line"><span>│   ├── domain/                 # Entities (Enterprise rules)</span></span>
<span class="line"><span>│   ├── errors/                 # ApiError, NotFoundError, BadRequestError</span></span>
<span class="line"><span>│   ├── usecases/               # Application business rules</span></span>
<span class="line"><span>│   ├── interfaces/             # Adapters</span></span>
<span class="line"><span>│   │   ├── controllers/        # Use next(error) for error propagation</span></span>
<span class="line"><span>│   │   └── routes/             # Pass NextFunction through handlers</span></span>
<span class="line"><span>│   ├── infrastructure/         # Frameworks &amp; Drivers</span></span>
<span class="line"><span>│   │   ├── config/             # Environment config</span></span>
<span class="line"><span>│   │   ├── caching/            # Redis Client</span></span>
<span class="line"><span>│   │   ├── database/           # DB connection &amp; models</span></span>
<span class="line"><span>│   │   ├── repositories/       # Data access implementation</span></span>
<span class="line"><span>│   │   └── webserver/</span></span>
<span class="line"><span>│   │       ├── middleware/</span></span>
<span class="line"><span>│   │       │   └── errorMiddleware.js  # JS only — Express error handler</span></span>
<span class="line"><span>│   │       └── server.js       # Express app setup</span></span>
<span class="line"><span>│   ├── utils/</span></span>
<span class="line"><span>│   │   └── errorMiddleware.ts  # TS — global error handler</span></span>
<span class="line"><span>│   └── index.js|ts              # Registers errorMiddleware after Apollo/Express</span></span>
<span class="line"><span>└── ...</span></span></code></pre></div><h3 id="case-d-clean-architecture-kafka-worker" tabindex="-1">Case D: Clean Architecture (Kafka Worker) <a class="header-anchor" href="#case-d-clean-architecture-kafka-worker" aria-label="Permalink to &quot;Case D: Clean Architecture (Kafka Worker)&quot;">​</a></h3><p>Optimized for event-driven microservices. HTTP routes are removed.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>project-name/</span></span>
<span class="line"><span>├── src/</span></span>
<span class="line"><span>│   ├── domain/</span></span>
<span class="line"><span>│   ├── usecases/</span></span>
<span class="line"><span>│   ├── infrastructure/</span></span>
<span class="line"><span>│   │   ├── config/             # Includes Kafka config</span></span>
<span class="line"><span>│   │   ├── database/</span></span>
<span class="line"><span>│   │   ├── messaging/          # Kafka Client/Consumer</span></span>
<span class="line"><span>│   │   ├── repositories/</span></span>
<span class="line"><span>│   │   └── webserver/          # (Optional/Minimal)</span></span>
<span class="line"><span>│   └── index.js|ts</span></span>
<span class="line"><span>└── ...</span></span></code></pre></div>`,31)])])}const h=s(o,[["render",r]]);export{u as __pageData,h as default};
